def parse_expr(tokens, options):
    """expr ::= seq ( '|' seq )* ;"""
    if not tokens.has_more():
        return []  # 或者返回一个合适的默认值
    seq = parse_seq(tokens, options)
    if tokens.current() != '|':
        return seq
    result = [Required(*seq)] if len(seq) > 1 else seq
    while tokens.current() == '|':
        tokens.move()
        if not tokens.has_more():
            break
        seq = parse_seq(tokens, options)
        result += [Required(*seq)] if len(seq) > 1 else seq
    return [Either(*result)] if len(result) > 1 else result

